          >
            Delete
          </button>
          <button
            onClick={handleExportCSV}
            className="px-3 py-1.5 text-sm bg-accent-blue text-white rounded hover:bg-accent-blue-hover transition-colors ml-auto"
          >
            Export CSV
          </button>
        </div>
      )}

