                onClick={() => handleSort('status')}
              >
                Status{getSortIndicator('status')}
              </th>
              <th
                className="p-3 text-left font-semibold text-text-light-primary dark:text-text-dark-primary cursor-pointer hover:bg-neutral-50 dark:hover:bg-neutral-800 transition-colors"
                onClick={() => handleSort('priority')}
              >
                Priority{getSortIndicator('priority')}
              </th>
              <th
                className="p-3 text-left font-semibold text-text-light-primary dark:text-text-dark-primary cursor-pointer hover:bg-neutral-50 dark:hover:bg-neutral-800 transition-colors"
                onClick={() => handleSort('dueDate')}
              >
                Due Date{getSortIndicator('dueDate')}
              </th>
              <th className="p-3 text-left font-semibold text-text-light-primary dark:text-text-dark-primary">
                Tags
              </th>
              <th className="p-3 text-left font-semibold text-text-light-primary dark:text-text-dark-primary">
                Progress
              </th>
