        <div className="mb-4 p-3 bg-accent-blue/10 dark:bg-accent-blue/20 border border-accent-blue rounded-lg flex items-center gap-3 flex-wrap">
          <span className="text-sm font-medium text-text-light-primary dark:text-text-dark-primary">
            {selectedTaskIds.size} selected
          </span>
          <button
            onClick={() => setShowStatusDialog(true)}
            className="px-3 py-1.5 text-sm bg-white dark:bg-neutral-800 border border-border-light dark:border-border-dark rounded hover:bg-neutral-50 dark:hover:bg-neutral-700 transition-colors"
          >
            Change Status
          </button>
          <button
            onClick={() => setShowPriorityDialog(true)}
            className="px-3 py-1.5 text-sm bg-white dark:bg-neutral-800 border border-border-light dark:border-border-dark rounded hover:bg-neutral-50 dark:hover:bg-neutral-700 transition-colors"
