/**
 * WikiLinkPlugin
 *
 * Lexical plugin for rendering wiki-style links ([[Note Title]]) with broken link detection.
 *
 * Features:
 * - Detects [[...]] patterns in text
 * - Renders as styled spans
 * - Different styling for existing vs broken links
 * - Click to navigate (existing) or create (broken)
 * - Updates when notes change
 */

import { useEffect } from 'react';
import { useLexicalComposerContext } from '@lexical/react/LexicalComposerContext';
import {
  $getRoot,
  $getSelection,
  $isRangeSelection,
  $isTextNode,
  TextNode,
  type LexicalNode,
} from 'lexical';
import type { Note } from '../../types/notes';

interface WikiLinkPluginProps {
  notes: Note[];
  onNavigate?: (noteId: string) => void;
  onCreate?: (title: string) => void;
}

const WIKI_LINK_PATTERN = /\[\[([^\]]+)\]\]/g;

export default function WikiLinkPlugin({
  notes,
  onNavigate,
  onCreate,
}: WikiLinkPluginProps) {
  const [editor] = useLexicalComposerContext();

  useEffect(() => {
    // Register update listener to transform wiki links
    const removeUpdateListener = editor.registerUpdateListener(({ editorState }) => {
      editorState.read(() => {
        const root = $getRoot();
        const textContent = root.getTextContent();

        // Only process if there are potential wiki links
        if (!textContent.includes('[[')) return;

        // Process all text nodes
        root.getAllTextNodes().forEach((textNode) => {
          const text = textNode.getTextContent();

          if (!text.includes('[[')) return;

          // Find wiki link patterns
          const matches = Array.from(text.matchAll(WIKI_LINK_PATTERN));

          if (matches.length === 0) return;

          // For each match, check if note exists and mark accordingly
          matches.forEach((match) => {
            const fullMatch = match[0]; // [[Title]]
            const linkTitle = match[1].trim();
            const matchIndex = match.index!;

            // Find note by title (case-insensitive exact match or partial)
            const linkedNote = notes.find(
              (note) => note.title.toLowerCase() === linkTitle.toLowerCase()
            ) || notes.find(
              (note) => note.title.toLowerCase().startsWith(linkTitle.toLowerCase())
            );

            // TODO: Apply styling based on linkedNote existence
            // This will require creating a custom DecoratorNode for wiki links
            // For now, we'll use a simpler approach with TextFormatting
          });
        });
      });
    });

    return removeUpdateListener;
  }, [editor, notes]);

  return null;
}

