     1→/**
     2→ * Graph Data Processor
     3→ * Transforms notes, tasks, and their relationships into graph data for visualization
     4→ */
     5→
     6→import type { Note } from '../types/notes';
     7→
     8→export interface GraphNode {
     9→  id: string;
    10→  type: 'note' | 'tag';
    11→  label: string;
    12→  color: string; // Semantic color token
    13→  size: number; // Based on connection count
    14→  metadata: {
    15→    createdAt?: string;
    16→    folder?: string;
    17→    tags?: string[];
    18→  };
    19→}
    20→
    21→export interface GraphEdge {
    22→  source: string; // Node ID
    23→  target: string; // Node ID
    24→  type: 'backlink' | 'tag';
    25→  strength: number; // For force simulation
    26→}
    27→
    28→export interface GraphData {
    29→  nodes: GraphNode[];
    30→  edges: GraphEdge[];
    31→}
    32→
    33→export interface GraphFilters {
    34→  searchQuery?: string;
    35→  selectedTags?: string[];
    36→  selectedFolders?: string[];
    37→  hideOrphans?: boolean;
    38→  focusNodeId?: string;
    39→  focusDepth?: number; // 1-3 hops from focused node
    40→}
    41→
    42→/**
    43→ * Get all nodes within N degrees of separation from a target node
    44→ * Uses breadth-first search to traverse the graph
    45→ */
    46→function getNodesWithinDepth(
    47→  nodeId: string,
    48→  depth: number,
    49→  edges: GraphEdge[]
    50→): Set<string> {
    51→  const visited = new Set<string>([nodeId]);
    52→  let currentLevel = [nodeId];
    53→
    54→  for (let d = 0; d < depth; d++) {
    55→    const nextLevel: string[] = [];
    56→
    57→    for (const current of currentLevel) {
    58→      // Find all directly connected nodes
    59→      const connected = edges
    60→        .filter(e => e.source === current || e.target === current)
    61→        .map(e => e.source === current ? e.target : e.source);
    62→
    63→      for (const neighbor of connected) {
    64→        if (!visited.has(neighbor)) {
    65→          visited.add(neighbor);
    66→          nextLevel.push(neighbor);
    67→        }
    68→      }
    69→    }
    70→
    71→    currentLevel = nextLevel;
    72→  }
    73→
    74→  return visited;
    75→}
    76→
    77→/**
    78→ * Build graph data from notes
    79→ */
    80→export function buildGraphData(
    81→  notes: Record<string, Note>,
    82→  filters: GraphFilters = {}
    83→): GraphData {
    84→  const nodes: GraphNode[] = [];
    85→  const edges: GraphEdge[] = [];
    86→  const nodeMap = new Map<string, GraphNode>();
    87→  const tagNodeMap = new Map<string, GraphNode>();
    88→
    89→  // Get all notes as array
    90→  const notesArray = Object.values(notes);
    91→
    92→  // Filter notes based on search/folder filters
    93→  let filteredNotes = notesArray;
    94→
    95→  if (filters.searchQuery) {
    96→    const query = filters.searchQuery.toLowerCase();
    97→    filteredNotes = filteredNotes.filter(
    98→      (note) =>
    99→        note.title.toLowerCase().includes(query) ||
   100→        note.content.toLowerCase().includes(query)
   101→    );
   102→  }
   103→
   104→  if (filters.selectedFolders && filters.selectedFolders.length > 0) {
   105→    filteredNotes = filteredNotes.filter((note) =>
   106→      filters.selectedFolders!.includes(note.folderId || 'root')
   107→    );
   108→  }
   109→
   110→  // Create note nodes
   111→  filteredNotes.forEach((note) => {
   112→    const node: GraphNode = {
   113→      id: note.id,
   114→      type: 'note',
   115→      label: note.title || 'Untitled',
   116→      color: 'var(--accent-cyan)', // Semantic token for notes
   117→      size: 10, // Base size, will be updated based on connections
   118→      metadata: {
   119→        createdAt: note.createdAt.toString(),
   120→        folder: note.folderId || undefined,
   121→        tags: note.tags || [],
   122→      },
   123→    };
   124→    nodes.push(node);
   125→    nodeMap.set(note.id, node);
   126→  });
   127→
   128→  // Create tag nodes and tag edges
   129→  const allTags = new Set<string>();
   130→  filteredNotes.forEach((note) => {
   131→    if (note.tags && note.tags.length > 0) {
   132→      note.tags.forEach((tag) => allTags.add(tag));
   133→    }
   134→  });
   135→
   136→  // Filter by selected tags if provided
   137→  let tagsToInclude = Array.from(allTags);
   138→  if (filters.selectedTags && filters.selectedTags.length > 0) {
   139→    tagsToInclude = tagsToInclude.filter((tag) =>
   140→      filters.selectedTags!.includes(tag)
   141→    );
   142→  }
   143→
   144→  tagsToInclude.forEach((tag) => {
   145→    const tagNode: GraphNode = {
   146→      id: `tag:${tag}`,
   147→      type: 'tag',
   148→      label: tag,
   149→      color: 'var(--accent-magenta)', // Semantic token for tags
   150→      size: 8, // Tags slightly smaller
   151→      metadata: {
   152→        tags: [tag],
   153→      },
   154→    };
   155→    nodes.push(tagNode);
   156→    tagNodeMap.set(tag, tagNode);
   157→  });
   158→
   159→  // Create tag edges (note → tag)
   160→  filteredNotes.forEach((note) => {
   161→    if (note.tags && note.tags.length > 0) {
   162→      note.tags.forEach((tag) => {
   163→        if (tagNodeMap.has(tag)) {
   164→          edges.push({
   165→            source: note.id,
   166→            target: `tag:${tag}`,
   167→            type: 'tag',
   168→            strength: 0.5, // Weaker than backlinks
   169→          });
   170→        }
   171→      });
   172→    }
   173→  });
   174→
   175→  // Create edges from linkedNotes (notes that this note links TO)
   176→  filteredNotes.forEach((note) => {
   177→    if (note.linkedNotes && note.linkedNotes.length > 0) {
   178→      note.linkedNotes.forEach((linkedNoteId: string) => {
   179→        // Only create edge if target note exists in filtered set
   180→        if (nodeMap.has(linkedNoteId)) {
   181→          edges.push({
   182→            source: note.id,
   183→            target: linkedNoteId,
   184→            type: 'backlink',
   185→            strength: 1.0, // Stronger connection
   186→          });
   187→        }
   188→      });
   189→    }
   190→  });
   191→
   192→  // Update node sizes based on connection count
   193→  const connectionCounts = new Map<string, number>();
   194→  edges.forEach((edge) => {
   195→    connectionCounts.set(edge.source, (connectionCounts.get(edge.source) || 0) + 1);
   196→    connectionCounts.set(edge.target, (connectionCounts.get(edge.target) || 0) + 1);
   197→  });
   198→
   199→  nodes.forEach((node) => {
   200→    const count = connectionCounts.get(node.id) || 0;
   201→    // Size scales with connections: 10-30 for notes, 8-20 for tags
   202→    const baseSize = node.type === 'note' ? 10 : 8;
   203→    const maxSize = node.type === 'note' ? 30 : 20;
   204→    node.size = Math.min(baseSize + count * 2, maxSize);
   205→  });
   206→
   207→  // Filter orphan nodes if requested
   208→  let finalNodes = nodes;
   209→  let finalEdges = edges;
   210→
   211→  if (filters.hideOrphans) {
   212→    const connectedNodeIds = new Set<string>();
   213→    edges.forEach((edge) => {
   214→      connectedNodeIds.add(edge.source);
   215→      connectedNodeIds.add(edge.target);
   216→    });
   217→    finalNodes = nodes.filter((node) => connectedNodeIds.has(node.id));
   218→  }
   219→
   220→  // Focus mode: show only nodes within N hops of focused node
   221→  if (filters.focusNodeId && filters.focusDepth) {
   222→    const focusedNodeIds = getNodesWithinDepth(
   223→      filters.focusNodeId,
   224→      filters.focusDepth,
   225→      edges
   226→    );
   227→
   228→    finalNodes = finalNodes.filter(n => focusedNodeIds.has(n.id));
   229→    finalEdges = edges.filter(e =>
   230→      focusedNodeIds.has(e.source) && focusedNodeIds.has(e.target)
   231→    );
   232→  }
   233→
   234→  return {
   235→    nodes: finalNodes,
   236→    edges: finalEdges,
   237→  };
   238→}
   239→
   240→/**
   241→ * Get unique folders from notes
   242→ */
   243→export function getUniqueFolders(notes: Record<string, Note>): string[] {
   244→  const folders = new Set<string>();
   245→  Object.values(notes).forEach((note) => {
   246→    if (note.folderId) {
   247→      folders.add(note.folderId);
   248→    } else {
   249→      folders.add('root');
   250→    }
   251→  });
   252→  return Array.from(folders);
   253→}
   254→
   255→/**
   256→ * Get unique tags from notes
   257→ */
   258→export function getUniqueTags(notes: Record<string, Note>): string[] {
