function generateColorPalette(count: number): string[] {
  const colors: string[] = [];
  const saturation = 70;
  const lightness = 55;

  for (let i = 0; i < count; i++) {
    // Distribute hues evenly around color wheel
    const hue = (i * 360) / count;
    colors.push(`hsl(${hue}, ${saturation}%, ${lightness}%)`);
  }

  return colors;
}

