### src/utils/graphDataProcessor.ts
**Why Important**: Transforms notes into graph visualization data
**Changes Made**: Added color grouping by folder/tag with HSL palette generation
**Key Code**:
```typescript
export interface GraphFilters {
  // ... existing filters
  colorBy?: 'folder' | 'tag' | 'none'; // P1: Color grouping
}

// Generate HSL color palette
function generateColorPalette(count: number): string[] {
  const colors: string[] = [];
  const saturation = 70;
  const lightness = 55;

  for (let i = 0; i < count; i++) {
    const hue = (i * 360) / count; // Even distribution
    colors.push(`hsl(${hue}, ${saturation}%, ${lightness}%)`);
  }
  return colors;
}

// Assign colors to nodes
function assignNodeColors(
  nodes: GraphNode[],
  colorBy: 'folder' | 'tag' | 'none'
): Map<string, string> {
  const colorMap = new Map<string, string>();

  if (colorBy === 'none') return colorMap;

  if (colorBy === 'folder') {
    const folders = new Set<string>();
    nodes.forEach((node) => {
      if (node.type === 'note') {
        folders.add(node.metadata.folder || 'root');
      }
    });

    const folderArray = Array.from(folders).sort();
    const palette = generateColorPalette(folderArray.length);

    folderArray.forEach((folder, index) => {
      colorMap.set(folder, palette[index]);
    });
  }

  // Similar for 'tag' grouping...
  return colorMap;
}

// Apply colors in buildGraphData
if (filters.colorBy && filters.colorBy !== 'none') {
  const colorMap = assignNodeColors(nodes, filters.colorBy);

  nodes.forEach((node) => {
    if (node.type === 'note') {
      let groupKey: string | undefined;

      if (filters.colorBy === 'folder') {
        groupKey = node.metadata.folder || 'root';
      } else if (filters.colorBy === 'tag' && node.metadata.tags?.length > 0) {
        groupKey = node.metadata.tags[0];
      }

      if (groupKey && colorMap.has(groupKey)) {
        node.color = colorMap.get(groupKey)!;
      }
    }
  });
}

// Export color groups for legend
export function getColorGroups(
  graphData: GraphData,
  colorBy: 'folder' | 'tag' | 'none'
): Map<string, { color: string; count: number }> {
  const groups = new Map();

  graphData.nodes.forEach((node) => {
    if (node.type === 'note') {
      let groupKey = colorBy === 'folder' 
        ? node.metadata.folder || 'root'
        : node.metadata.tags?.[0];

      if (groupKey) {
        const existing = groups.get(groupKey);
        if (existing) {
          existing.count++;
        } else {
          groups.set(groupKey, { color: node.color, count: 1 });
        }
      }
    }
  });

  return groups;
}
```

