export type StrokeStyle = 'solid' | 'dashed' | 'dotted';
export type FontWeight = 'normal' | 'bold';
export type TextAlign = 'left' | 'center' | 'right';
export type ConnectorType = 'straight' | 'curved' | 'orthogonal';

export interface Point {
  x: number;
  y: number;
}

export interface CanvasState {
  zoom: number; // 1.0 = 100%
  pan: Point; // viewport offset
  gridSize: number; // 20px default
  snapToGrid: boolean;
}

export interface DiagramElement {
  id: string;
  type: DiagramElementType;

  // Position & size
  x: number;
  y: number;
  width: number;
  height: number;
  rotation?: number; // degrees

  // Styling
  fill?: string; // hex color or 'transparent'
  stroke?: string;
  strokeWidth?: number;
  strokeStyle?: StrokeStyle;
  cornerRadius?: number; // for rectangles

  // Text-specific
  text?: string;
  fontSize?: number;
  fontFamily?: string;
  fontWeight?: FontWeight;
  textAlign?: TextAlign;

  // Connector-specific
  startPoint?: Point;
  endPoint?: Point;
  startShapeId?: string; // smart connector source
  endShapeId?: string; // smart connector target
  startArrow?: boolean;
  endArrow?: boolean;
  connectorType?: ConnectorType;

  // Path-specific (freehand)
  points?: Point[];

  // Z-index
  zIndex: number;
}

export interface Diagram {
  id: string;
  title: string;
  createdAt: Date;
  updatedAt: Date;
  thumbnail?: string; // base64 PNG

  // Canvas state
  canvasState: CanvasState;

  // Elements
  elements: DiagramElement[];

  // Metadata
  tags?: string[];
  linkedNotes?: string[];
  linkedTasks?: string[];
}

export type ToolType = 'select' | 'rectangle' | 'circle' | 'line' | 'arrow' | 'text' | 'pen' | 'connector';

export interface EditorState {
  currentTool: ToolType;
  selectedElementIds: string[];
  clipboard: DiagramElement[];
  isDragging: boolean;
  isDrawing: boolean;
}

export interface HistoryEntry {
  elements: DiagramElement[];
  canvasState: CanvasState;
}

export interface ExportOptions {
  format: 'png' | 'svg' | 'pdf' | 'json';
  fullDiagram?: boolean; // export entire diagram vs current viewport
  scale?: number; // for PNG export (1 = normal, 2 = 2x resolution)
}

