     1→/**
     2→ * Forms Store
     3→ * Manages form templates and responses with IndexedDB persistence
     4→ */
     5→
     6→import { create } from 'zustand';
     7→import { persist } from 'zustand/middleware';
     8→import type {
     9→  FormTemplate,
    10→  FormResponse,
    11→  FormWithStats,
    12→} from '../types/forms';
    13→
    14→interface FormsState {
    15→  // Form templates
    16→  forms: FormTemplate[];
    17→  createForm: (title: string, description?: string) => FormTemplate;
    18→  updateForm: (id: string, updates: Partial<FormTemplate>) => void;
    19→  deleteForm: (id: string) => void;
    20→  getForm: (id: string) => FormTemplate | undefined;
    21→  duplicateForm: (id: string) => FormTemplate | undefined;
    22→
    23→  // Form responses
    24→  responses: FormResponse[];
    25→  submitResponse: (formId: string, answers: Record<string, any>) => FormResponse;
    26→  deleteResponse: (id: string) => void;
    27→  getResponses: (formId: string) => FormResponse[];
    28→  clearFormResponses: (formId: string) => void;
    29→
    30→  // Statistics
    31→  getFormWithStats: (id: string) => FormWithStats | undefined;
    32→  getAllFormsWithStats: () => FormWithStats[];
    33→}
    34→
    35→export const useFormsStore = create<FormsState>()(
    36→  persist(
    37→    (set, get) => ({
    38→      forms: [],
    39→      responses: [],
    40→
    41→      // Create new form template
    42→      createForm: (title, description) => {
    43→        const newForm: FormTemplate = {
    44→          id: crypto.randomUUID(),
    45→          title,
    46→          description,
    47→          fields: [],
    48→          createdAt: new Date(),
    49→          updatedAt: new Date(),
    50→          settings: {
    51→            allowMultipleSubmissions: true,
    52→            showSubmissionCount: true,
    53→            resetPeriod: 'never',
    54→          },
    55→        };
    56→
    57→        set((state) => ({
    58→          forms: [...state.forms, newForm],
    59→        }));
    60→
    61→        return newForm;
    62→      },
    63→
    64→      // Update existing form
    65→      updateForm: (id, updates) => {
    66→        set((state) => ({
    67→          forms: state.forms.map((form) =>
    68→            form.id === id
    69→              ? { ...form, ...updates, updatedAt: new Date() }
    70→              : form
    71→          ),
    72→        }));
    73→      },
    74→
    75→      // Delete form and all its responses
    76→      deleteForm: (id) => {
    77→        set((state) => ({
    78→          forms: state.forms.filter((form) => form.id !== id),
    79→          responses: state.responses.filter((response) => response.formId !== id),
    80→        }));
    81→      },
    82→
    83→      // Get form by ID
    84→      getForm: (id) => {
    85→        return get().forms.find((form) => form.id === id);
    86→      },
    87→
    88→      // Duplicate form
    89→      duplicateForm: (id) => {
    90→        const original = get().getForm(id);
    91→        if (!original) return undefined;
    92→
    93→        const duplicate: FormTemplate = {
    94→          ...original,
    95→          id: crypto.randomUUID(),
    96→          title: `${original.title} (Copy)`,
    97→          createdAt: new Date(),
    98→          updatedAt: new Date(),
    99→          fields: original.fields.map((field) => ({
   100→            ...field,
   101→            id: crypto.randomUUID(), // New IDs for fields
   102→          })),
   103→        };
   104→
   105→        set((state) => ({
   106→          forms: [...state.forms, duplicate],
   107→        }));
   108→
   109→        return duplicate;
   110→      },
   111→
   112→      // Submit form response
   113→      submitResponse: (formId, answers) => {
   114→        const newResponse: FormResponse = {
   115→          id: crypto.randomUUID(),
   116→          formId,
   117→          answers,
   118→          submittedAt: new Date(),
   119→        };
   120→
   121→        set((state) => ({
   122→          responses: [...state.responses, newResponse],
   123→        }));
   124→
   125→        return newResponse;
   126→      },
   127→
   128→      // Delete single response
   129→      deleteResponse: (id) => {
   130→        set((state) => ({
   131→          responses: state.responses.filter((response) => response.id !== id),
   132→        }));
   133→      },
   134→
   135→      // Get all responses for a form
   136→      getResponses: (formId) => {
   137→        return get().responses.filter((response) => response.formId === formId);
   138→      },
   139→
   140→      // Clear all responses for a form
   141→      clearFormResponses: (formId) => {
   142→        set((state) => ({
   143→          responses: state.responses.filter((response) => response.formId !== formId),
   144→        }));
   145→      },
   146→
   147→      // Get form with statistics
   148→      getFormWithStats: (id) => {
   149→        const form = get().getForm(id);
   150→        if (!form) return undefined;
   151→
   152→        const formResponses = get().getResponses(id);
   153→        const sortedResponses = formResponses.sort(
   154→          (a, b) =>
   155→            new Date(b.submittedAt).getTime() - new Date(a.submittedAt).getTime()
   156→        );
   157→
   158→        return {
   159→          ...form,
   160→          responseCount: formResponses.length,
   161→          lastSubmittedAt:
   162→            sortedResponses.length > 0 ? sortedResponses[0].submittedAt : undefined,
   163→        };
