</div>

{/* P0: Advanced Options (Conditional Logic) */}
<div className="border-t border-border-light dark:border-border-dark pt-4">
  <button
    type="button"
    onClick={() => setShowAdvancedOptions(!showAdvancedOptions)}
    className="flex items-center justify-between w-full text-left text-sm font-medium text-text-light-primary dark:text-text-dark-primary hover:text-accent-magenta transition-colors"
  >
    <span>Advanced Options</span>
